 试题B 既约分数
如果一个分数的分子和分母的最大公约数是1，这个分数称为既约分数。例如，3/43/43/4 ， 5/25/25/2 ， 1/81/81/8  ， 7/17/17/1 都是既约分数。请问，有多少个既约分数，分子和分母都是1 到2020 之间的整数（包括1和2020）？
#include &lt;iostream&gt;
using namespace std;
int GreatestCommonDivisor(int a, int b)
&#123;
    if (a &#x3D;&#x3D; 0 || b &#x3D;&#x3D; 0)
        return 1;
    int tmp;
    while (a % b !&#x3D; 0)
    &#123;
        tmp &#x3D; a;
        a &#x3D; b;
        b &#x3D; tmp % b;
    &#125;
    return b;
&#125;
int main()
&#123;
    int sum &#x3D; 0;
    for (int i &#x3D; 1; i &lt; 2021; i++)
        for (int j &#x3D; 1; j &lt; 2021; j++)
            if (GreatestCommonDivisor(i, j) &#x3D;&#x3D; 1)
                sum++;
    cout &lt;&lt; sum;
&#125;
